"""
MKT Christ Commentary — 1 Chronicles chapters 16–18
Run: python3 scripts/zc-christ-1chronicles-16-18.py

Ch16: Composite psalm (Ps 105+96+106) — universal praise mission, Parousia anticipation (16:33-34)
Ch17: The Davidic covenant oracle — Heb 1:5 (17:13), eternal throne (17:14), temple-building Son (17:12)
Ch18: David's just reign as the conquering-king type of Christ's universal dominion (18:14)

Note: 17:14 already present from earlier stub — merge_comm will skip it.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "16": {
    "1": "<p>The Ark of God was brought in and set inside the tent that David had pitched for it — the installation of the divine presence in Jerusalem. David&rsquo;s pitched tent (<em>ʾōhel</em>) for the Ark is a provisional dwelling that anticipates the permanent temple — just as the Incarnation is described as God pitching his tent among us (&lsquo;dwelt&rsquo; in John 1:14 is <em>eskēnōsen</em>, &lsquo;tented&rsquo;). The Ark&rsquo;s installation in Jerusalem is the OT event most directly prefiguring the Incarnation&rsquo;s arrival: the divine presence comes to dwell in the covenant city, in a human-prepared structure, as the center of worship.</p>",
    "2": "<p>David blessed the people in the name of YHWH — the Aaronic blessing invoked by the king at the Ark&rsquo;s installation. The priest-king who blesses the people is the Melchizedek pattern (Gen 14:18-20: Melchizedek, king and priest, blessed Abram; Heb 7:1-3). David is not a priest by tribe (he is from Judah) yet acts in a priestly-blessing capacity at the sacred moment of the Ark&rsquo;s installation. This priestly-royal overlap in David prefigures the Messiah who holds both offices simultaneously: &lsquo;a priest forever after the order of Melchizedek&rsquo; (Ps 110:4; Heb 5:6), who is also the Davidic king.</p>",
    "3": "<p>David distributed to each Israelite, both man and woman, a loaf of bread, a portion of meat, and a raisin cake. The king distributes food to the entire people at the Ark&rsquo;s installation — a communal feast. The feeding of the whole community by the king at the presence-of-God moment prefigures Jesus&rsquo;s feeding of the multitudes (Matt 14:19-21; John 6:1-14), which John explicitly interprets as a &lsquo;sign&rsquo; of Jesus as the bread of life. At the Ark&rsquo;s arrival = distribution of bread; at the Presence of God made flesh = distribution of the bread of life.</p>",
    "4": "<p>David appointed Levites to minister before the Ark of YHWH, to invoke, to thank, and to praise YHWH the God of Israel. The three-part liturgical role — invoke (<em>lizkîr</em>), thank (<em>lᵉhôḏôt</em>), praise (<em>lᵉhallēl</em>) — is the comprehensive structure of Israel&rsquo;s worship. The NT applies all three to the Messiah&rsquo;s priestly intercession: Christ invokes (Heb 7:25: &lsquo;he always lives to make intercession&rsquo;), thanks (Matt 26:26-27: he gave thanks over bread and cup), and praises (Heb 2:12: &lsquo;I will tell of your name to my brothers; in the midst of the congregation I will sing your praise&rsquo;, citing Ps 22:22).</p>",
    "5": "<p>Asaph the chief, Zechariah second, Jeiel, Shemiramoth, Jehiel, Mattithiah, Eliab, Benaiah, Obed-edom, and Jeiel — the Levitical musicians appointed to the Ark. The musical praise community established at the Ark&rsquo;s installation is the institutional form of what Rev 5:8-10 describes in the throne-room: &lsquo;each holding a harp, and golden bowls full of incense, which are the prayers of the saints. And they sang a new song.&rsquo; The earthly Ark-worship of harps and song is a type of the heavenly throne-worship.</p>",
    "6": "<p>The priests Benaiah and Jahaziel were to blow trumpets regularly before the Ark of God&rsquo;s covenant. The covenant trumpets sound before the Ark — the signal of covenant assembly and divine attention (Num 10:9-10). Rev 8-11: the seven trumpets that announce the divine judgments leading to the final coronation of Christ reflect the covenantal-trumpet pattern established at the Ark&rsquo;s installation. Covenant presence = trumpet-sound before the throne.</p>",
    "7": "<p>On that day David first appointed that thanks be given to YHWH by Asaph and his brothers. The &lsquo;first&rsquo; day of appointed praise — the inauguration of the Levitical praise-ministry before the Ark — is the OT beginning of the institutional worship that prefigures the Church&rsquo;s doxological existence. Heb 2:12 cites Ps 22:22 (&lsquo;in the midst of the congregation I will praise you&rsquo;) as Christ&rsquo;s own singing of praise among his brothers — the first day of Christian worship is the day Christ rose and appeared to his disciples, establishing the new covenant assembly of praise.</p>",
    "8": "<p>&lsquo;Oh give thanks to YHWH; call upon his name; make known his deeds among the peoples!&rsquo; The composite psalm begins with an invitation to covenant praise that is simultaneously missional: making YHWH&rsquo;s deeds known among the peoples (<em>bāʿammîm</em>) takes the praise beyond Israel. The missions theology of the NT — &lsquo;that you may proclaim the excellencies of him who called you out of darkness into his marvelous light&rsquo; (1 Pet 2:9) — carries forward this Ark-installation mandate. The purpose of Israel&rsquo;s distinctive covenant worship was always proclamation among the nations.</p>",
    "9": "<p>&lsquo;Sing to him, sing praises to him; tell of all his wondrous works!&rsquo; The call to song and narrative-proclamation of YHWH&rsquo;s works. The NT worship of Christ includes both song (&lsquo;singing psalms and hymns and spiritual songs,&rsquo; Col 3:16) and proclamation of his mighty acts (Acts 2:11: the disciples speaking &lsquo;the mighty works of God&rsquo; at Pentecost). The dual form of praise — sung and spoken — reflects the composite structure of this inaugural psalm.</p>",
    "10": "<p>&lsquo;Glory in his holy name; let the hearts of those who seek YHWH rejoice!&rsquo; The holy name is the covenant name — YHWH, the I-AM of covenant faithfulness. Those who seek YHWH&rsquo;s face (v11) rejoice in his name. Acts 2:21 (citing Joel 2:32): &lsquo;everyone who calls on the name of the Lord will be saved&rsquo; — the holy name in which David&rsquo;s psalm calls for glory is the same name in which NT salvation is received. The psalm&rsquo;s holy-name praise is fulfilled in the name &lsquo;Jesus,&rsquo; the covenant name that saves (Matt 1:21).</p>",
    "11": "<p>&lsquo;Seek YHWH and his strength; seek his presence continually!&rsquo; The call to continuous divine-presence-seeking frames the Ark&rsquo;s installation as an invitation, not merely a ceremony: the covenant presence is sought, not merely hosted. Heb 11:6: &lsquo;whoever would draw near to God must believe that he exists and that he rewards those who seek him.&rsquo; The seeking-imperative of David&rsquo;s installation psalm is the OT form of the NT faith-claim: the covenant God is One who responds to those who seek him.</p>",
    "12": "<p>&lsquo;Remember the wondrous works that he has done, his miracles, and the judgments he uttered.&rsquo; Covenant memory — the active remembrance (<em>zikrōn</em>) of YHWH&rsquo;s historical acts — is the foundation of Israel&rsquo;s worship. The NT eucharist institutionalizes this anamnesis: &lsquo;Do this in remembrance of me&rsquo; (Luke 22:19; 1 Cor 11:24-25). The Ark-installation psalm&rsquo;s call to &lsquo;remember the wondrous works&rsquo; is recapitulated every time the Lord&rsquo;s Supper proclaims the Lord&rsquo;s death until he comes (1 Cor 11:26).</p>",
    "13": "<p>&lsquo;O offspring of Israel his servant, children of Jacob, his chosen ones!&rsquo; The covenant identity of YHWH&rsquo;s people — offspring of the servant-patriarch. Paul applies servant-language to Christ himself (the Servant Songs of Isaiah fulfilled in Jesus; Matt 12:18 cites Isa 42:1); the collective servant-identity of Israel is fulfilled individually in the Servant par excellence, whose people share his servant status (Mark 10:44-45: &lsquo;whoever would be great among you must be your servant, even as the Son of Man came not to be served but to serve&rsquo;).</p>",
    "14": "<p>&lsquo;He is YHWH our God; his judgments are in all the earth.&rsquo; The universal reach of YHWH&rsquo;s covenant-lordship — his judgments are not confined to Israel but extend to all the earth. Rom 3:6: &lsquo;Otherwise, how could God judge the world?&rsquo; The universal divine judgeship announced at the Ark&rsquo;s installation becomes the framework for Paul&rsquo;s argument in Romans about universal human accountability to the one God whose covenant lordship encompasses all nations.</p>",
    "15": "<p>&lsquo;Remember his covenant forever, the word that he commanded for a thousand generations.&rsquo; The covenant is eternally remembered — YHWH himself keeps his own covenant in divine memory. The thousand-generation timeframe effectively means forever (Deut 7:9: &lsquo;keeping covenant and steadfast love with those who love him and keep his commandments, to a thousand generations&rsquo;). Heb 13:20: &lsquo;the God of peace who brought again from the dead our Lord Jesus, the great shepherd of the sheep, by the blood of the eternal covenant&rsquo; — the Davidic/Abrahamic covenant becomes the &lsquo;eternal covenant&rsquo; in its NT fulfillment in Christ&rsquo;s blood.</p>",
    "16": "<p>&lsquo;The covenant that he made with Abraham, his sworn oath to Isaac.&rsquo; The Abrahamic covenant is the foundation beneath the Davidic installation psalm — YHWH&rsquo;s history with his people goes back to the oath sworn to Abraham. Gal 3:16: &lsquo;the promises were made to Abraham and to his offspring. It does not say &ldquo;and to offsprings,&rdquo; referring to many, but referring to one, &ldquo;and to your offspring,&rdquo; who is Christ.&rsquo; The Abrahamic covenant remembered in the Ark-installation psalm finds its ultimate single fulfillment in Christ.</p>",
    "17": "<p>&lsquo;He confirmed it to Jacob as a statute, to Israel as an everlasting covenant.&rsquo; The Abrahamic-Isaacic-Jacobine chain of covenant confirmation leads to Israel as the covenant people — and through Israel to the Messiah. The &lsquo;everlasting covenant&rsquo; (<em>bᵉrît ʿôlām</em>) language connects to Jer 31:31-34 (new everlasting covenant) and Heb 13:20 (eternal covenant in Christ&rsquo;s blood). Each generation&rsquo;s covenant-confirmation is a link in the chain leading to the covenant&rsquo;s ultimate instantiation in Christ.</p>",
    "18": "<p>&lsquo;Saying, &ldquo;To you I will give the land of Canaan as your portion for an inheritance.&rdquo;&rsquo; The land-promise embedded in the Ark-installation psalm. Heb 4:8-11 reinterprets the land-rest: Joshua&rsquo;s land-giving did not produce the ultimate rest; a Sabbath-rest still awaits the people of God. The land-promise of the covenant (to Abraham, reiterated here at the Ark&rsquo;s arrival in the covenant land&rsquo;s capital city) is fulfilled eschatologically in the &lsquo;inheritance that is imperishable, undefiled, and unfading, kept in heaven for you&rsquo; (1 Pet 1:4).</p>",
    "19": "<p>&lsquo;When you were few in number, of little account, and sojourners in it.&rsquo; The covenant people&rsquo;s humble, alien origin — they were not native inhabitants but sojourners. 1 Pet 2:11: &lsquo;I urge you as sojourners and exiles&rsquo; — the NT returns to the sojourner-identity as the permanent status of the covenant community. Christ himself was a sojourner in his own creation (&lsquo;he came to his own, and his own people did not receive him,&rsquo; John 1:11); his community shares his alien status in the world.</p>",
    "20": "<p>&lsquo;Wandering from nation to nation, from one kingdom to another people.&rsquo; The patriarchal wandering — Abraham, Isaac, Jacob moving through Canaan, Egypt, Mesopotamia without a fixed home. Heb 11:9-10: &lsquo;By faith he [Abraham] went to live in the land of promise, as in a foreign land, living in tents with Isaac and Jacob, heirs with him of the same promise. For he was looking forward to the city that has foundations, whose designer and builder is God.&rsquo; The wandering through nations finds its rest only in the city that God builds — the new Jerusalem, the ultimate covenant home.</p>",
    "21": "<p>&lsquo;He allowed no one to oppress them; he rebuked kings on their account.&rsquo; YHWH&rsquo;s protection of the small wandering covenant community against the surrounding kingdoms — Pharaoh, Abimelech, and others are rebuked for threatening the patriarchal family. Rom 8:31: &lsquo;If God is for us, who can be against us?&rsquo; — the NT applies the patriarchal protection pattern to the covenant community in Christ: YHWH&rsquo;s rebuke of kings for the sake of his covenant people is the OT form of the NT promise that &lsquo;neither death nor life... nor things present nor things to come... will be able to separate us from the love of God in Christ Jesus our Lord&rsquo; (Rom 8:38-39).</p>",
    "22": "<p>&lsquo;Touch not my anointed ones, do my prophets no harm!&rsquo; The divine protection of the <em>mᵉšîḥāyw</em> (anointed ones) — the patriarchal family as YHWH&rsquo;s anointed community. The title <em>māšîaḥ</em> (anointed/Messiah/Christ) is here applied collectively to the covenant community but reaches its individual climax in the Messiah par excellence. Ps 2:2 (cited in Acts 4:26-27) uses the same title for the unique Anointed One whom the kings of the earth conspire against; the protection promised to the covenant anointed community is fulfilled in the resurrection of the Christ whom death could not hold.</p>",
    "23": "<p>&lsquo;Sing to YHWH, all the earth! Tell of his salvation from day to day.&rsquo; The universal mission expands: not Israel only but &lsquo;all the earth&rsquo; is called to sing YHWH&rsquo;s salvation. <em>Yᵉšûʿātô</em> (his salvation) — the same root as the name &lsquo;Jesus&rsquo; (Yēšûaʿ). The psalm embedded in the Ark-installation celebrates a salvation that is universal in scope — a prophecy fulfilled when the name of Jesus is proclaimed as salvation to all the earth (Acts 4:12: &lsquo;there is salvation in no one else, for there is no other name under heaven given among men by which we must be saved&rsquo;).</p>",
    "24": "<p>&lsquo;Declare his glory among the nations, his marvelous works among all the peoples!&rsquo; The dual imperative of the Great Commission in psalmic form: declare glory to nations, declare works among peoples. Matt 28:19-20 is the fulfillment: &lsquo;Go therefore and make disciples of all nations... teaching them to observe all that I have commanded you.&rsquo; The installation of the Ark in Jerusalem came with a psalm that pointed beyond Jerusalem to the nations — and the Ark&rsquo;s anti-type, the incarnate Christ, sent his disciples to the very ends of the earth.</p>",
    "25": "<p>&lsquo;For great is YHWH, and greatly to be praised, and he is to be feared above all gods.&rsquo; The incomparability of YHWH — <em>ʿal kol ʾelōhîm</em>, above all gods. Phil 2:9-11: &lsquo;God has highly exalted him and bestowed on him the name that is above every name, so that at the name of Jesus every knee should bow... and every tongue confess that Jesus Christ is Lord.&rsquo; The incomparability-praise of the Ark-installation psalm becomes the Christological acclamation of the cosmic coronation: above all rivals, above all thrones, above all names.</p>",
    "26": "<p>&lsquo;For all the gods of the peoples are idols, but YHWH made the heavens.&rsquo; The polemic against idolatry embedded in the coronation psalm — the covenant God is the creator of the heavens that the idol-gods inhabit (or are claimed to inhabit). 1 Cor 8:4-6: &lsquo;we know that &ldquo;an idol has no real existence&rdquo;... yet for us there is one God, the Father, from whom are all things... and one Lord, Jesus Christ, through whom are all things.&rsquo; The monotheistic cosmological claim of the Ark-installation psalm is repeated and Christologically applied in the NT: the one Creator is the Father of Christ, and Christ himself is the agent of creation.</p>",
    "27": "<p>&lsquo;Splendor and majesty are before him; strength and joy are in his place.&rsquo; The divine attributes surrounding YHWH&rsquo;s throne — splendor, majesty, strength, joy — are the throne-room qualities the NT throne-visions describe. Rev 4:11: &lsquo;Worthy are you, our Lord and God, to receive glory and honor and power, for you created all things.&rsquo; The four-fold attribute cluster of the coronation psalm becomes the content of the heavenly throne-room acclamation.</p>",
    "28": "<p>&lsquo;Ascribe to YHWH, O clans of the peoples, ascribe to YHWH glory and strength!&rsquo; The invitation to the nations&rsquo; clans (<em>mišpᵉḥôt ʿammîm</em>) to ascribe glory and strength to YHWH. Rev 7:9-10: &lsquo;a great multitude that no one could number, from every nation, from all tribes and peoples and languages, standing before the throne and before the Lamb, crying out with a loud voice, &ldquo;Salvation belongs to our God who sits on the throne, and to the Lamb!&rdquo;&rsquo; — the nations-praise invitation of the Ark-installation psalm is fulfilled in the multinational throne-room worship of the Lamb.</p>",
    "29": "<p>&lsquo;Ascribe to YHWH the glory due his name; bring an offering and come before him! Worship YHWH in the splendor of holiness.&rsquo; The offering-and-worship imperative — covenant worship requires both declaration (&lsquo;ascribe glory&rsquo;) and presentation (&lsquo;bring an offering&rsquo;). Heb 13:15-16: &lsquo;Through him then let us continually offer up a sacrifice of praise to God... and do not neglect to do good and to share what you have, for such sacrifices are pleasing to God.&rsquo; The NT translates the offering of the Ark-psalm into the sacrifice of praise and the sharing of goods — the same dual structure of worship.</p>",
    "30": "<p>&lsquo;Tremble before him, all the earth! Yes, the world is established; it shall never be moved.&rsquo; Cosmic stability grounded in YHWH&rsquo;s lordship — the earth is established (tikkôn) because the covenant God rules. Heb 12:28: &lsquo;let us be grateful for receiving a kingdom that cannot be shaken.&rsquo; The Ark-psalm&rsquo;s cosmic stability language becomes the NT&rsquo;s kingdom-stability promise: the kingdom Christ brings is the one unshakeable reality in a cosmos that will be shaken and remade (Heb 12:26-27: &lsquo;yet once more I will shake not only the earth but also the heavens&rsquo;).</p>",
    "31": "<p>&lsquo;Let the heavens be glad, and let the earth rejoice, and let them say among the nations, &ldquo;YHWH reigns!&rdquo;&rsquo; The cosmic coronation-shout — heaven and earth rejoicing in YHWH&rsquo;s reign, with the message &lsquo;YHWH reigns&rsquo; (<em>YHWH mālāk</em>) proclaimed to the nations. Rev 11:15: &lsquo;The kingdom of the world has become the kingdom of our Lord and of his Christ, and he shall reign forever and ever.&rsquo; The <em>YHWH mālāk</em> proclamation of the Ark-psalm is the OT form of the throne-room coronation-shout of the Apocalypse.</p>",
    "32": "<p>&lsquo;Let the sea roar, and all that fills it; let the field exult, and everything in it!&rsquo; The whole creation joins the coronation praise — seas, fields, and their inhabitants. Rom 8:19-22: &lsquo;the creation waits with eager longing for the revealing of the sons of God... the creation itself will be set free from its bondage to corruption.&rsquo; Creation&rsquo;s praise in the Ark-psalm is proleptic — the sea, field, and forest are commanded to praise now what will be fully realized at the Parousia; Paul&rsquo;s &lsquo;eager longing&rsquo; of creation awaits the same moment the psalm&rsquo;s command anticipates.</p>",
    "33": "<p>&lsquo;Then shall the trees of the forest sing for joy before YHWH, for he comes to judge the earth.&rsquo; The coming of YHWH as judge — <em>kî bāʾ lišpōṭ ʾet hāʾāreṣ</em>, &lsquo;for he comes to judge the earth&rsquo; — is the Parousia-anticipation embedded in the Ark-installation psalm. The coming judge is anticipated by singing creation; when he arrives, the cosmos&rsquo;s long-anticipated hope is fulfilled. Matt 25:31: &lsquo;When the Son of Man comes in his glory, and all the angels with him, then he will sit on his glorious throne.&rsquo; The judgment-coming of Christ is the fulfillment of the psalm&rsquo;s &lsquo;he comes to judge.&rsquo;</p>",
    "34": "<p>&lsquo;Oh give thanks to YHWH, for he is good; for his steadfast love endures forever!&rsquo; The tôḏāh/ḥesed formula — the refrain from Ps 136 and Ps 118. Ps 118:1 (same formula) is the psalm from which &lsquo;Hosanna! Blessed is he who comes in the name of the Lord!&rsquo; derives (Ps 118:25-26 = Matt 21:9) — the Palm Sunday entrance is textually connected to this Ark-installation formula. The ḥesed that &lsquo;endures forever&rsquo; (Hebrew <em>lᵉʿôlām ḥasdô</em>) is the unchanging divine love that the Messiah embodies: &lsquo;Jesus Christ is the same yesterday and today and forever&rsquo; (Heb 13:8).</p>",
    "35": "<p>&lsquo;Say also: &ldquo;Save us, O God of our salvation, and gather us and deliver us from among the nations, that we may give thanks to your holy name and glory in your praise.&rdquo;&rsquo; The petition for divine salvation and re-gathering from the nations is placed within the coronation psalm — even at the moment of Ark-installation, the exilic-dispersion future is anticipated and prayed through. Luke 1:68-69: &lsquo;Blessed be the Lord God of Israel, for he has visited and redeemed his people and has raised up a horn of salvation for us in the house of his servant David&rsquo; — Zechariah&rsquo;s Benedictus is a NT fulfillment of this embedded Ark-psalm petition for salvation, gathering, and deliverance.</p>",
    "36": "<p>&lsquo;Blessed be YHWH the God of Israel from everlasting to everlasting!&rsquo; The doxological conclusion of the composite psalm. Rev 1:8: &lsquo;I am the Alpha and the Omega, says the Lord God, who is and who was and who is to come, the Almighty.&rsquo; The &lsquo;everlasting to everlasting&rsquo; (<em>mēhāʿôlām wᵉʿaḏ hāʿôlām</em>) doxology of the Ark-installation psalm is fulfilled in Christ&rsquo;s self-identification as the One who encompasses all time. The whole people said &lsquo;Amen&rsquo; and praised YHWH — the covenant congregation&rsquo;s &lsquo;Amen&rsquo; (Hebrew &lsquo;so be it&rsquo;; Greek <em>amēn</em>) is the acclamation Christ uses to introduce his authoritative teaching (&lsquo;Truly, truly I say to you,&rsquo; John 1:51 etc.) and that Rev 3:14 applies as his title: &lsquo;the Amen, the faithful and true witness.&rsquo;</p>",
    "37": "<p>David left Asaph and his brothers there before the Ark of the covenant of YHWH to minister regularly before the Ark. The permanent appointment of the praise-community before the Ark establishes continuous worship as the covenant norm — worship does not end after the installation feast but continues &lsquo;regularly&rsquo; (<em>lᵉyôm bᵉyômô</em>, day by day). Heb 13:15: &lsquo;Through him then let us continually offer up a sacrifice of praise to God&rsquo; — the &lsquo;continually&rsquo; of NT praise echoes the &lsquo;regularly&rsquo; of the Ark-worship: covenant presence demands continuous praise response.</p>",
    "38": "<p>Obed-edom and his sixty-eight brothers served as gatekeepers. Obed-edom — the Gittite in whose house the Ark rested for three months after Uzzah&rsquo;s death (13:14) and who was blessed by YHWH during that period — is now appointed as a gatekeeper-servant of the Ark. His trajectory from hosting the Ark in fear (13:13-14) to serving the Ark in appointment reflects the covenant community&rsquo;s movement from holy dread to commissioned service. The pattern recurs in the disciples who fell on their faces at the Transfiguration (Matt 17:6) and were commissioned at the resurrection (Matt 28:19).</p>",
    "39": "<p>Zadok the priest and his brothers the priests were before the tabernacle of YHWH in the high place at Gibeon. The dual-sanctuary arrangement (Ark in Jerusalem, tabernacle at Gibeon) is formally institutionalized. Zadok serves the Mosaic tabernacle at Gibeon while Asaph serves the Davidic Ark-tent in Jerusalem — two legitimate worship sites serving one covenant community. The NT&rsquo;s Christological synthesis removes the geographic duality: Jesus tells the Samaritan woman &lsquo;neither on this mountain nor in Jerusalem will you worship the Father... true worshipers will worship the Father in spirit and truth&rsquo; (John 4:21-23).</p>",
    "40": "<p>Zadok and his brothers were to offer burnt offerings to YHWH on the altar of burnt offering regularly, morning and evening, according to all that is written in the Law of YHWH. The Mosaic law&rsquo;s tamid (regular morning-and-evening sacrifice, Exod 29:38-43) continues at Gibeon even as the new Jerusalem worship begins. Heb 10:1-4: the daily sacrifices could never take away sins; they are a shadow of the good things to come. The tamid&rsquo;s daily repetition points to its own incompleteness — fulfilled once-for-all in Christ&rsquo;s single sacrifice (Heb 10:10-14).</p>",
    "41": "<p>With them were Heman and Jeduthun and the rest of those chosen and expressly named to give thanks to YHWH, for his steadfast love endures forever. The <em>ḥesed</em>-refrain (&lsquo;his steadfast love endures forever&rsquo;) is the theological core of the appointed thanksgiving-singers&rsquo; mission. The permanence of divine <em>ḥesed</em> is the ground of all covenant worship — and its NT expression is the love of Christ that &lsquo;surpasses knowledge&rsquo; (Eph 3:19) and from which nothing can separate (Rom 8:35-39).</p>",
    "42": "<p>Heman and Jeduthun had trumpets and cymbals for the music, and instruments for sacred song. The worship-equipment at Gibeon is specified: trumpets (priestly signal instruments), cymbals (rhythmic/percussive), and instruments for sacred song. The full instrumental array of OT worship — Ps 150 culminates with every instrument — is a type of the comprehensive praise of the new creation where all of creation&rsquo;s capacities are directed to the Creator&rsquo;s glory.</p>",
    "43": "<p>Then all the people departed each to his house, and David went home to bless his household. The close of the Ark-installation day: the king returns to his house to bless his family after blessing the whole people (v2). The circle of blessing — from the cosmic (all earth, v23) to the national (all Israel) to the domestic (his household) — reflects the covenant&rsquo;s concentric structure. The blessing Christ brings operates at all levels simultaneously: cosmic reconciliation (Col 1:20), ecclesial peace (Eph 2:14-17), and household transformation (Eph 5:22-6:4).</p>"
  },
  "17": {
    "1": "<p>David said to Nathan: &lsquo;Behold, I dwell in a house of cedar, but the Ark of the covenant of YHWH is under a tent.&rsquo; The contrast David identifies — his own cedar-paneled palace versus the tent sheltering the divine presence — is the impulse behind the temple project. The NT reframes the contrast: the greatest possible &lsquo;contrast&rsquo; was God&rsquo;s eternal, uncreated glory emptied into a human body (&lsquo;though he was rich, yet for your sake he became poor,&rsquo; 2 Cor 8:9). David&rsquo;s impulse to honor the divine presence with the best structure mirrors the disciples&rsquo; impulse to prepare for Christ&rsquo;s coming — but the NT answer is not a building but a community: &lsquo;you yourselves are God&rsquo;s temple&rsquo; (1 Cor 3:16).</p>",
    "2": "<p>Nathan said to David: &lsquo;Do all that is in your heart, for God is with you.&rsquo; Nathan&rsquo;s initial favorable response to David&rsquo;s temple plan — given without consulting YHWH — is immediately overridden by YHWH&rsquo;s night-oracle (v3). The contrast between human discernment (&lsquo;God is with you — do it&rsquo;) and divine revelation (&lsquo;not you but your son&rsquo;) is significant: prophetic discernment requires direct divine instruction, not just pious inference. The NT pattern: the disciples&rsquo; human understanding of the kingdom (Acts 1:6: &lsquo;will you at this time restore the kingdom to Israel?&rsquo;) is corrected by Christ&rsquo;s post-resurrection instruction (Acts 1:7-8).</p>",
    "3": "<p>&lsquo;That same night the word of God came to Nathan&rsquo; — the divine word overriding Nathan&rsquo;s initial assent. The pattern of divine corrective revelation: God does not let pious human initiative proceed unchecked when his purposes are different. Christ frequently corrected pious-but-mistaken assumptions: &lsquo;Get behind me, Satan!&rsquo; to Peter after his good-intentioned objection (Mark 8:33); the correction of the Emmaus disciples&rsquo; failed messianic expectations (Luke 24:25-27). The divine word that comes at night redirects Nathan&rsquo;s day-counsel: revelation supersedes inference.</p>",
    "4": "<p>&lsquo;Go and tell my servant David, &ldquo;Thus says YHWH: It is not you who will build me a house to dwell in.&rdquo;&rsquo; The divine refusal of David&rsquo;s temple-project is addressed to &lsquo;my servant David&rsquo; — the honorific title that places the refusal within an affirming relationship. David is still YHWH&rsquo;s servant; the refusal is not rejection but redirection. 2 Cor 1:19-20: in Christ, all the promises of God are &lsquo;Yes&rsquo; — not every &lsquo;no&rsquo; in redemptive history is a permanent negative; YHWH&rsquo;s &lsquo;not you&rsquo; becomes &lsquo;your son&rsquo; (v12), and the son&rsquo;s temple anticipates the Son who is himself the temple.</p>",
    "5": "<p>&lsquo;I have not lived in a house since the day I brought up Israel to this day, but I have gone from tent to tent and from dwelling to dwelling.&rsquo; YHWH&rsquo;s declaration of his own history of mobile dwelling — tent to tent, dwelling to dwelling. The divine preference for mobility over fixity is theologically significant: John 1:14 uses the tent-word (<em>eskēnōsen</em>) for the Incarnation — God&rsquo;s ultimate dwelling is not a stone building but a human body. The entire history of YHWH going &lsquo;from tent to tent&rsquo; culminates in the tent of Christ&rsquo;s flesh.</p>",
    "6": "<p>&lsquo;In all places where I have moved with all Israel, did I speak a word with any of the judges of Israel, whom I commanded to shepherd my people, saying, &ldquo;Why have you not built me a house of cedar?&rdquo;&rsquo; YHWH has never requested a cedar temple from any of his covenant representatives. The absence of a temple-requirement through the entire pre-Davidic period shows that the temple is a later accommodation, not an original divine mandate. Stephen&rsquo;s speech (Acts 7:44-50) makes exactly this argument: the tabernacle sufficed; the temple was Solomon&rsquo;s work; the Most High does not dwell in houses made by human hands. The divine freedom from temple-fixity is preserved even as the temple is permitted.</p>",
    "7": "<p>&lsquo;Now therefore thus shall you say to my servant David: Thus says YHWH of hosts, I took you from the pasture, from following the sheep, to be leader over my people Israel.&rsquo; The Davidic covenant oracle opens with the shepherd-king&rsquo;s origin: taken from the sheep-pasture. The divine election of the shepherd-king is the type of Christ&rsquo;s origin: born in a stable in Bethlehem, the shepherd-city (Mic 5:2). The NT&rsquo;s good shepherd image (John 10) traces to this pastoral origin: the Messiah comes from the place of shepherds, not from the palace.</p>",
    "8": "<p>&lsquo;And I have been with you wherever you went and have cut off all your enemies before you. And I will make for you a name, like the name of the great ones of the earth.&rsquo; YHWH&rsquo;s past faithfulness to David (cutting off enemies) grounds the covenant promise. Phil 2:9-11: &lsquo;God has highly exalted him and bestowed on him the name that is above every name&rsquo; — the promise of the &lsquo;great name&rsquo; given to David (a secondary type) is surpassed in the Name that is above every name given to the risen Christ. The name-making in the Davidic covenant is the OT shadow of the supreme naming at the resurrection-exaltation.</p>",
    "9": "<p>&lsquo;I will appoint a place for my people Israel and will plant them, that they may dwell in their own place and be disturbed no more. And violent men shall waste them no more, as formerly.&rsquo; The promise of covenant-place-security — Israel planted, not uprooted; established, not disturbed. John 14:2-3: &lsquo;In my Father&rsquo;s house are many rooms. If it were not so, would I have told you that I go to prepare a place for you?&rsquo; — Christ promises to prepare a <em>topos</em> (place) for his people; the Davidic covenant&rsquo;s place-promise (a secure dwelling in the land) is fulfilled in the eschatological place Christ prepares.</p>",
    "10": "<p>&lsquo;And from the time that I appointed judges over my people Israel. And I will subdue all your enemies. Moreover, I declare to you that YHWH will build you a house.&rsquo; The covenant climax reversal: David proposed to build YHWH a house; YHWH declares that he will build David a house. The house-building reversal is the Davidic covenant&rsquo;s central insight: the covenant king does not give to God what God needs; God gives to the covenant king what only God can provide — a dynasty. Eph 2:20-22: &lsquo;built on the foundation of the apostles and prophets, Christ Jesus himself being the cornerstone, in whom the whole structure, being joined together, grows into a holy temple in the Lord&rsquo; — God builds the true temple, not humanity.</p>",
    "11": "<p>&lsquo;When your days are fulfilled to walk with your fathers, I will raise up your offspring after you, one of your own sons, and I will establish his kingdom.&rsquo; The Davidic succession-promise: after David&rsquo;s death, YHWH will raise up his son. &lsquo;Raise up&rsquo; (<em>hăqîmôtî</em>) — the same verbal root used for resurrection in the NT: &lsquo;God raised him from the dead&rsquo; (Acts 2:32; 13:33-34, where Paul explicitly cites the Davidic covenant: &lsquo;I will give you the holy and sure blessings of David&rsquo; in connection with Christ&rsquo;s resurrection). The raising-up of David&rsquo;s son becomes the type of the raising-up of David&rsquo;s greater Son from the dead.</p>",
    "12": "<p>&lsquo;He shall build a house for me, and I will establish his throne forever.&rsquo; The son who builds the house (Solomon, the immediate fulfillment) and the throne that is established forever (Christ, the ultimate fulfillment). John 2:19-21: Jesus said &lsquo;Destroy this temple, and in three days I will raise it up.&rsquo; The disciples later understood that &lsquo;he was speaking about the temple of his body.&rsquo; The greater Son builds the true and eternal temple — not Solomon&rsquo;s stone structure but the resurrection-body, the living stones of the Church (1 Pet 2:5), and ultimately the new Jerusalem where God dwells with his people (Rev 21:3).</p>",
    "13": "<p>&lsquo;I will be to him a father, and he shall be to me a son. I will not take my steadfast love from him as I took it from him who was before you.&rsquo; This is the verse cited in Heb 1:5 as applying to Christ in its ultimate sense: &lsquo;For to which of the angels did God ever say, &ldquo;You are my Son, today I have begotten you&rdquo;? Or again, &ldquo;I will be to him a father, and he shall be to me a son&rdquo;?&rsquo; The Davidic covenant language of divine fatherhood and sonship becomes the NT&rsquo;s primary Christological category: Christ is the Son in whom the Father&rsquo;s eternal paternal love is fully expressed. The <em>ḥesed</em>-qualification — &lsquo;I will not take my steadfast love from him&rsquo; — is fulfilled in Christ absolutely: the love of God poured out in him is permanent and unconditional (Rom 8:38-39).</p>",
    "15": "<p>Nathan reported all these words and all this vision to David. The prophet as the mediator between divine revelation and the covenant king — Nathan delivers YHWH&rsquo;s oracle verbatim to David. The prophetic office of mediating divine speech to the covenant community reaches its climax in Christ: &lsquo;In many and various ways God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son&rsquo; (Heb 1:1-2). Nathan mediates the Davidic covenant; the Son is simultaneously the mediator and the content of the new covenant.</p>",
    "16": "<p>King David went in and sat before YHWH and said: &lsquo;Who am I, O YHWH God, and what is my house, that you have brought me thus far?&rsquo; David&rsquo;s prayer of humble amazement at the covenant promise received. The posture of humility before covenant grace is the NT&rsquo;s paradigm for the covenant community&rsquo;s response to election: &lsquo;But God chose what is foolish in the world to shame the wise; God chose what is weak in the world to shame the strong&rsquo; (1 Cor 1:27). David&rsquo;s &lsquo;who am I?&rsquo; is the model response to divine election: not worthiness-claim but awe-filled gratitude.</p>",
    "17": "<p>&lsquo;And this was a small thing in your eyes, O God. You have also spoken of your servant&rsquo;s house for a great while to come.&rsquo; The &lsquo;great while to come&rsquo; (<em>lᵉmērāḥôq</em>, &lsquo;from afar&rsquo; / &lsquo;for a long way&rsquo;) in the Chronicler&rsquo;s version acknowledges the eschatological horizon of the covenant promise: the Davidic house&rsquo;s future stretches far beyond David&rsquo;s own lifetime. 2 Pet 3:8-9: &lsquo;with the Lord one day is as a thousand years, and a thousand years as one day&rsquo; — the divine long-term perspective of the Davidic covenant is the covenant logic that the NT inherits: God plans in millennia, not merely years.</p>",
    "18": "<p>&lsquo;What more can David add to you for honoring your servant? For you know your servant.&rsquo; David&rsquo;s recognition that YHWH already knows him — the divine knowing (<em>yāḏaʿtā ʾet ʿaḇdᵉḵā</em>) precedes and makes possible the covenant. John 10:14-15: &lsquo;I am the good shepherd. I know my own and my own know me, just as the Father knows me and I know the Father.&rsquo; The divine knowing is the relational foundation of the shepherd-covenant: David&rsquo;s &lsquo;you know your servant&rsquo; anticipates Christ&rsquo;s mutual-knowing with the Father that extends to include his sheep.</p>",
    "19": "<p>&lsquo;O YHWH, for your servant&rsquo;s sake and according to your own heart, you have done all this greatness, making known all these great things.&rsquo; The divine initiative in the covenant — YHWH has done this &lsquo;according to your own heart&rsquo; (<em>kᵉlibbᵉḵā</em>), not according to David&rsquo;s merit. The Davidic covenant is unconditional in its origin: it springs from God&rsquo;s own sovereign love. Eph 1:4-5: &lsquo;he chose us in him before the foundation of the world... according to the purpose of his will.&rsquo; The &lsquo;according to your own heart&rsquo; of the Davidic covenant becomes the &lsquo;according to the purpose of his will&rsquo; of election in Christ.</p>",
    "20": "<p>&lsquo;O YHWH, there is none like you, and there is no God besides you, according to all that we have heard with our ears.&rsquo; The incomparability-confession at the heart of David&rsquo;s response: no god compares to YHWH. 1 Cor 8:6: &lsquo;for us there is one God, the Father, from whom are all things and for whom we exist, and one Lord, Jesus Christ, through whom are all things and through whom we exist.&rsquo; The NT Christological monotheism is the fulfillment of the Davidic incomparability-confession: YHWH&rsquo;s uniqueness now includes the identity of his Son and Spirit within the one divine being.</p>",
    "21": "<p>&lsquo;And who is like your people Israel, the one nation on earth whom God went to redeem to be his people, making for yourself a name for great and awesome things, by driving out nations before your people whom you redeemed from Egypt?&rsquo; The exodus-redemption as the foundational covenant act — YHWH redeemed Israel &lsquo;to be his people&rsquo; (<em>lô lᵉʿām</em>). 1 Pet 2:9: &lsquo;you are a chosen race, a royal priesthood, a holy nation, a people for his own possession&rsquo; — citing Exod 19:5-6 through an Isaianic lens. The NT applies Israel&rsquo;s &lsquo;his people&rsquo; identity to the Church gathered from all nations in Christ.</p>",
    "22": "<p>&lsquo;And you made your people Israel to be your people forever, and you, O YHWH, became their God.&rsquo; The covenant formula — &lsquo;you will be my people and I will be your God&rsquo; — stated from the human side as an accomplished fact. Rev 21:3: &lsquo;Behold, the dwelling place of God is with man. He will dwell with them, and they will be his people, and God himself will be with them as their God.&rsquo; The covenant formula that begins with &lsquo;I will be your God&rsquo; in Exod 6:7, runs through David&rsquo;s prayer here, and reaches its eschatological consummation in Rev 21&rsquo;s new creation where the formula is finally and permanently fulfilled.</p>",
    "23": "<p>&lsquo;And now, O YHWH, let the word that you have spoken concerning your servant and concerning his house be established forever, and do as you have spoken.&rsquo; David prays the covenant oracle back to YHWH — praying YHWH&rsquo;s own promise as the content of his petition. This pattern of praying God&rsquo;s word back to him is the OT model for covenant prayer. The Lord&rsquo;s Prayer operates on the same logic: &lsquo;your kingdom come, your will be done on earth as it is in heaven&rsquo; — asking God to accomplish what he has promised. The Davidic covenant prayer is the structural model for the eschatological petition.</p>",
    "24": "<p>&lsquo;And let your name be established and magnified forever, saying, &ldquo;YHWH of hosts, the God of Israel, is Israel&rsquo;s God,&rdquo; and the house of your servant David is established before you.&rsquo; The double establishment: the divine name and the Davidic house, each confirmed by the other. The NT achieves both: &lsquo;at the name of Jesus every knee should bow&rsquo; (Phil 2:10) — the divine name is magnified; and &lsquo;of his kingdom there will be no end&rsquo; (Luke 1:33) — the Davidic house is established forever.</p>",
    "25": "<p>&lsquo;For you, my God, have revealed to your servant that you will build him a house. Therefore your servant has found courage to pray before you.&rsquo; Covenant revelation provides the ground for covenant confidence in prayer: because YHWH has spoken the promise, David dares to pray. Heb 4:16: &lsquo;let us then with confidence draw near to the throne of grace, that we may receive mercy and find grace to help in time of need.&rsquo; The NT&rsquo;s boldness in prayer before the throne is equally grounded in the divine promise — the revelation of the new covenant in Christ&rsquo;s blood is the foundation for &lsquo;confidence to enter the holy places by the blood of Jesus&rsquo; (Heb 10:19).</p>",
    "26": "<p>&lsquo;O YHWH, you are God and you have promised this good thing to your servant.&rsquo; David&rsquo;s affirmation of YHWH&rsquo;s identity and promise: &lsquo;you are God&rsquo; grounds the confidence in the promise. The prayer closes by returning to YHWH&rsquo;s character as the foundation for covenant expectation. Rom 4:21: Abraham was &lsquo;fully convinced that God was able to do what he had promised&rsquo; — the same covenant confidence that David expresses here is the pattern of faith that Paul presents as paradigmatic.</p>",
    "27": "<p>&lsquo;Now you have been pleased to bless the house of your servant, that it may continue forever before you, for it is you, O YHWH, who have blessed it, and it is blessed forever.&rsquo; The closing benediction: the Davidic house is blessed forever because YHWH has blessed it — and YHWH&rsquo;s blessing cannot be revoked. The Christological fulfillment: the risen Christ &lsquo;always lives to make intercession&rsquo; (Heb 7:25) — his intercessory life before the Father is the permanent covenant-blessing that can never be removed. The Davidic house&rsquo;s &lsquo;forever&rsquo; becomes the &lsquo;always&rsquo; of Christ&rsquo;s perpetual priesthood-kingship.</p>"
  },
  "18": {
    "1": "<p>David defeated the Philistines and subdued them and took Gath and its villages from the hand of the Philistines. David&rsquo;s military campaigns in ch 18 establish his reign as the conquering-king type: systematic territorial expansion through YHWH&rsquo;s enabling power. The Christological type: Eph 1:20-22: &lsquo;he raised him from the dead and seated him at his right hand in the heavenly places, far above all rule and authority and power and dominion... and put all things under his feet.&rsquo; David&rsquo;s territorial conquest-sequence is the shadow of Christ&rsquo;s resurrection-conquest of all powers.</p>",
    "2": "<p>He defeated Moab, and the Moabites became servants to David and brought tribute. The Moabite submission prefigures Ps 2:8-9: &lsquo;Ask of me, and I will make the nations your heritage, and the ends of the earth your possession. You shall break them with a rod of iron and dash them in pieces like a potter&rsquo;s vessel.&rsquo; David&rsquo;s military submission of surrounding nations is the temporal shadow of the eschatological submission of all nations to the Messiah (Phil 2:10-11: &lsquo;every knee should bow... and every tongue confess that Jesus Christ is Lord&rsquo;).</p>",
    "3": "<p>David defeated Hadadezer king of Zobah toward Hamath, as he went to extend his power at the Euphrates. The Euphrates as the boundary of the promised land (Gen 15:18: &lsquo;from the river of Egypt to the great river, the river Euphrates&rsquo;) — David&rsquo;s campaign to the Euphrates approaches the full extent of the covenant land-promise. The eschatological fulfillment: Christ inherits &lsquo;the ends of the earth&rsquo; (Ps 2:8) — a dominion that far exceeds even the Euphrates boundary.</p>",
    "4": "<p>David took from him 1,000 chariots, 7,000 horsemen, and 20,000 foot soldiers. And David hamstrung all the chariot horses, but left enough for 100 chariots. The hamstringing of the horses is a deliberate obedience to the Deuteronomic kingship law (Deut 17:16: &lsquo;he must not acquire many horses for himself&rsquo;). David refuses to base his power on military technology. The NT pattern: &lsquo;Not by might, nor by power, but by my Spirit, says YHWH of hosts&rsquo; (Zech 4:6) — the kingdom that Christ establishes is not established by superior military capacity.</p>",
    "5": "<p>When the Syrians of Damascus came to help Hadadezer king of Zobah, David struck down 22,000 men of the Syrians. And YHWH gave victory to David wherever he went. The refrain &lsquo;YHWH gave victory to David wherever he went&rsquo; (<em>wayyôšaʿ YHWH ʾet dāwîḏ bᵉḵōl ʾăšer hālaḵ</em>) is the theological key to the conquest-sequence: the victories are YHWH&rsquo;s gift, not David&rsquo;s achievement. 1 Cor 15:57: &lsquo;But thanks be to God, who gives us the victory through our Lord Jesus Christ.&rsquo; The divine gift of victory to David is the type of the divine gift of resurrection-victory to Christ and through Christ to his people.</p>",
    "6": "<p>David put garrisons in Syria of Damascus, and the Syrians became servants to David and brought tribute. And YHWH gave victory to David wherever he went. The second occurrence of the &lsquo;YHWH gave victory&rsquo; refrain (cf. v5) emphasizes the divine enablement. The garrisons in Damascus are administrative structures of peace following military victory — not mere domination but governance. The Messianic kingdom similarly replaces conflict with ordered rule: &lsquo;of the increase of his government and of peace there will be no end&rsquo; (Isa 9:7).</p>",
    "7": "<p>And David took the golden shields that were carried by the servants of Hadadezer and brought them to Jerusalem. The war-trophies of conquered kings brought to Jerusalem are a type of the spoils of Christ&rsquo;s victory: Eph 4:8 (citing Ps 68:18): &lsquo;When he ascended on high he led a host of captives, and he gave gifts to men.&rsquo; The triumphal procession&rsquo;s spoils in both the Davidic and NT contexts are redistributed as gifts to the community — David brings the shields to Jerusalem; Christ distributes spiritual gifts (apostles, prophets, evangelists, pastors, teachers) to the Church.</p>",
    "8": "<p>And from Tibhath and from Cun, cities of Hadadezer, David took very much bronze. With it Solomon made the bronze sea and the pillars and the vessels of bronze. The captured bronze becomes the material for Solomon&rsquo;s temple — the spoils of David&rsquo;s conquest are transformed into the worship-furnishings of YHWH&rsquo;s house. The pattern: the enemy&rsquo;s resources, taken in battle, are repurposed for divine worship. The NT applies the same logic to the powers&rsquo; defeat: Col 2:15 (&lsquo;he disarmed the rulers and authorities... triumphing over them in him&rsquo;) — the cross&rsquo;s apparent defeat of Christ becomes the instrument of the enemy&rsquo;s rout, repurposed as the means of salvation.</p>",
    "9": "<p>When Tou king of Hamath heard that David had struck down the whole army of Hadadezer king of Zobah, he sent his son Hadoram to King David, to ask about his health and to bless him. The king of a distant kingdom voluntarily seeks peace with David after witnessing his military power. Ps 72:10-11: &lsquo;May the kings of Tarshish and of the coastlands render him tribute; may the kings of Sheba and Seba bring gifts. May all kings fall down before him, all nations serve him!&rsquo; — the voluntary tribute of distant kings prophesied for the Messianic king begins with David&rsquo;s reception of Tou&rsquo;s embassy.</p>",
    "10": "<p>Hadoram brought vessels of gold, silver, and bronze — the diplomatic gifts of the Hamath king. The voluntary tribute of precious metals from distant kingdoms is fulfilled in the magi&rsquo;s gifts to the infant Christ (Matt 2:11: gold, frankincense, and myrrh) — the first fulfillment of Ps 72:10-11 (&lsquo;kings of Sheba and Seba bring gifts&rsquo;). The tribute pattern from David&rsquo;s foreign victories to the magi&rsquo;s gifts is the Christological arc: the greater David receives richer tribute from a wider geography.</p>",
    "11": "<p>These also King David dedicated to YHWH, together with the silver and gold that he had carried off from all the nations, from Edom, Moab, the Ammonites, the Philistines, and Amalek. The dedication of all war-spoils to YHWH is the theological climax of the conquest-sequence: the wealth of the nations is channeled through YHWH&rsquo;s king into YHWH&rsquo;s treasury for YHWH&rsquo;s purposes. Isa 60:5: &lsquo;the wealth of the nations shall come to you&rsquo; — the Messianic prophecy of nations&rsquo; wealth flowing to Zion is anticipated in David&rsquo;s dedicatory practice.</p>",
    "12": "<p>Abishai the son of Zeruiah struck down 18,000 Edomites in the Valley of Salt. David&rsquo;s military commanders extending the conquest — the king&rsquo;s victories are multiplied through his delegates. The NT pattern: the apostles and disciples carry the victory of Christ into the world, extending his reign not by additional death but by proclamation. &lsquo;As the Father has sent me, even so I am sending you&rsquo; (John 20:21) — the commission delegates the king&rsquo;s authority to his servants.</p>",
    "13": "<p>David put garrisons in Edom, and all the Edomites became David&rsquo;s servants. And YHWH gave victory to David wherever he went. The third occurrence of the victory-refrain in ch 18 (v5, v6, v13) forms a theological triad: YHWH&rsquo;s victory is the consistent cause behind David&rsquo;s consistent territorial expansion. The eschatological consummation: &lsquo;The God of peace will soon crush Satan under your feet&rsquo; (Rom 16:20) — the triple victory-refrain pattern is the OT form of the NT&rsquo;s victory-assurance through Christ.</p>",
    "14": "<p>So David reigned over all Israel, and he administered justice and righteousness to all his people. The summary of David&rsquo;s reign — &lsquo;justice and righteousness&rsquo; (<em>mišpāṭ ûṣᵉḏāqāh</em>) to all his people. Isa 9:7: &lsquo;of the increase of his government and of peace there will be no end, on the throne of David and over his kingdom, to establish it and to uphold it with justice and with righteousness from this time forth and forevermore.&rsquo; Jer 23:5: &lsquo;I will raise up for David a righteous Branch, and he shall reign as king and deal wisely, and shall execute justice and righteousness in the land.&rsquo; The Davidic justice-and-righteousness formula is the OT&rsquo;s defining Messianic criterion; Christ is its fulfillment: &lsquo;he is the propitiation for our sins, and not for ours only but also for the sins of the whole world&rsquo; (1 John 2:2) — the righteousness he establishes is not merely political but cosmic and redemptive.</p>",
    "15": "<p>Joab the son of Zeruiah was over the army; Jehoshaphat the son of Ahilud was recorder. David&rsquo;s administrative officials are named — the royal court whose offices are organized around the justice-and-righteousness mandate of v14. The NT church&rsquo;s office-holders (Eph 4:11-13) similarly organize the covenant community around the righteousness-mission of the greater David: apostles, prophets, evangelists, pastors, and teachers equipping the community for its justice-and-righteousness witness.</p>",
    "16": "<p>Zadok son of Ahitub and Ahimelech son of Abiathar were priests; Shavsha was secretary. The dual priests in David&rsquo;s court — Zadok and Ahimelech — anticipate the single high priest of the new covenant: Christ himself, who holds the priestly office permanently and without division (Heb 7:23-25: &lsquo;the former priests were many in number, because they were prevented by death from continuing in office, but he holds his priesthood permanently, because he continues forever&rsquo;).</p>",
    "17": "<p>Benaiah the son of Jehoiada was over the Cherethites and the Pelethites; and David&rsquo;s sons were the chief officials in the service of the king. The royal administration is complete: military (Joab), priestly (Zadok, Ahimelech), secretarial (Shavsha), judicial/diplomatic (Jehoshaphat), personal guard (Benaiah), and family officials (David&rsquo;s sons). The comprehensive governance-structure of the ideal Davidic king is a type of the universal governance-structure of the Messianic kingdom: &lsquo;the government shall be upon his shoulder&rsquo; (Isa 9:6) — Christ governs the totality of the covenant community&rsquo;s life, not merely one sector.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', '1chronicles')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', '1chronicles', c)
    count = sum(len(v) for v in CHRIST.values())
    print(f'1chronicles mkt-christ: wrote {count} verses across ch 16-18')

if __name__ == '__main__':
    main()
